  1→import { useEffect, useRef, type ReactNode } from 'react';
  2→import './alert.scss';
  3→
  4→export type AlertActionStyle = 'default' | 'destructive' | 'cancel';
  5→
  6→export interface AlertAction {
  7→  label: string;
  8→  style?: AlertActionStyle;
  9→  onAction: () => void;
 10→}
 11→
 12→export interface AlertOptions {
 13→  title: string;
 14→  message?: string;
 15→  icon?: ReactNode;
 16→  primaryAction: AlertAction;
 17→  dismissAction?: AlertAction;
 18→}
 19→
 20→interface AlertProps extends AlertOptions {
 21→  onDismiss: () => void;
 22→}
 23→
 24→function AlertIcon({ icon }: { icon?: ReactNode }) {
 25→  if (!icon) return null;
 26→  return <div className="alert__icon">{icon}</div>;
 27→}
 28→
 29→export function Alert({
 30→  title,
 31→  message,
 32→  icon,
 33→  primaryAction,
 34→  dismissAction,
 35→  onDismiss,
 36→}: AlertProps) {
 37→  const dialogRef = useRef<HTMLDivElement>(null);
 38→  const primaryRef = useRef<HTMLButtonElement>(null);
 39→
 40→  useEffect(() => {
 41→    primaryRef.current?.focus();
 42→  }, []);
 43→
 44→  useEffect(() => {
 45→    function handleKeyDown(e: KeyboardEvent) {
 46→      if (e.key === 'Escape') {
 47→        e.preventDefault();
 48→        e.stopPropagation();
 49→        if (dismissAction) {
 50→          dismissAction.onAction();
 51→        }
 52→        onDismiss();
 53→        return;
 54→      }
 55→      if (e.key === 'Tab') {
 56→        const focusable = dialogRef.current?.querySelectorAll<HTMLElement>(
 57→          'button:not([disabled])',
 58→        );
 59→        if (!focusable || focusable.length === 0) return;
 60→
 61→        const first = focusable.item(0);
 62→        const last = focusable.item(focusable.length - 1);
 63→        if (!first || !last) return;
 64→
 65→        if (e.shiftKey) {
 66→          if (document.activeElement === first) {
 67→            e.preventDefault();
 68→            last.focus();
 69→          }
 70→        } else {
 71→          if (document.activeElement === last) {
 72→            e.preventDefault();
 73→            first.focus();
 74→          }
 75→        }
 76→      }
 77→    }
 78→
 79→    window.addEventListener('keydown', handleKeyDown, true);
 80→    return () => window.removeEventListener('keydown', handleKeyDown, true);
 81→  }, [
 82→    onDismiss,
 83→    dismissAction,
 84→  ]);
 85→
 86→  function handleBackdropClick(e: React.MouseEvent) {
 87→    if (e.target === e.currentTarget) {
 88→      if (dismissAction) {
 89→        dismissAction.onAction();
 90→      }
 91→      onDismiss();
 92→    }
 93→  }
 94→
 95→  function handlePrimaryClick() {
 96→    primaryAction.onAction();
 97→    onDismiss();
 98→  }
 99→
100→  function handleDismissClick() {
101→    if (dismissAction) {
102→      dismissAction.onAction();
103→    }
104→    onDismiss();
105→  }
106→
107→  const primaryClassName = `alert__button alert__button--${primaryAction.style ?? 'default'}`;
108→
109→  return (
110→    <div
111→      className="alert__backdrop"
112→      onClick={handleBackdropClick}
113→      role="presentation"
114→    >
115→      <div
116→        className="alert__dialog"
117→        ref={dialogRef}
118→        role="alertdialog"
119→        aria-modal="true"
120→        aria-labelledby="alert-title"
121→        aria-describedby={message ? 'alert-message' : undefined}
122→      >
123→        <AlertIcon icon={icon} />
124→        <h2 className="alert__title" id="alert-title">
125→          {title}
126→        </h2>
127→        {message && (
128→          <p className="alert__message" id="alert-message">
129→            {message}
130→          </p>
131→        )}
132→        <div className="alert__actions">
133→          {dismissAction && (
134→            <button
135→              type="button"
136→              className="alert__button alert__button--cancel"
137→              onClick={handleDismissClick}
138→            >
139→              {dismissAction.label}
140→            </button>
141→          )}
142→          <button
143→            type="button"
144→            className={primaryClassName}
145→            onClick={handlePrimaryClick}
146→            ref={primaryRef}
147→          >
148→            {primaryAction.label}
149→          </button>
150→        </div>
151→      </div>
152→    </div>
153→  );
154→}
