 1→import { useCallback, useState } from 'react';
 2→import type { AlertOptions } from '../components/alert/alert';
 3→
 4→interface AlertState extends AlertOptions {
 5→  resolve: (confirmed: boolean) => void;
 6→}
 7→
 8→export function useAlert() {
 9→  const [alertState, setAlertState] = useState<AlertState | null>(null);
10→
11→  const confirmAlert = useCallback((
12→    options: AlertOptions,
13→  ): Promise<boolean> => {
14→    return new Promise<boolean>(resolve => {
15→      const wrappedOptions: AlertState = {
16→        ...options,
17→        primaryAction: {
18→          ...options.primaryAction,
19→          onAction: () => {
20→            options.primaryAction.onAction();
21→            resolve(true);
22→          },
23→        },
24→        dismissAction: options.dismissAction
25→          ? {
26→              ...options.dismissAction,
27→              onAction: () => {
28→                options.dismissAction!.onAction();
29→                resolve(false);
30→              },
31→            }
32→          : {
33→              label: 'Cancel',
34→              style: 'cancel' as const,
35→              onAction: () => {
36→                resolve(false);
37→              },
38→            },
39→        resolve,
40→      };
41→      setAlertState(wrappedOptions);
42→    });
43→  }, []);
44→
45→  const dismiss = useCallback(() => {
46→    if (alertState) {
47→      alertState.resolve(false);
48→    }
49→    setAlertState(null);
50→  }, [alertState]);
51→
52→  return {
53→    alertState,
54→    confirmAlert,
55→    dismiss,
56→  };
57→}
