 32→function filterSections(sections: SectionData[], query: string): SectionData[] {
 33→  if (!query) return sections;
 34→  const lower = query.toLowerCase();
 35→  return sections
 36→    .map(section => ({
 37→      ...section,
 38→      items: section.items.filter(
 39→        item =>
 40→          item.title.toLowerCase().includes(lower) ||
 41→          item.subtitle?.toLowerCase().includes(lower),
 42→      ),
 43→    }))
 44→    .filter(section => section.items.length > 0);
 45→}
 46→
 47→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 48→  if (!query) return colors;
 49→  const lower = query.toLowerCase();
 50→  return colors.filter(
 51→    c =>
 52→      c.title.toLowerCase().includes(lower) ||
 53→      c.subtitle?.toLowerCase().includes(lower),
 54→  );
 55→}
 56→
 57→function flattenItems(sections: SectionData[]): ListItemData[] {
 58→  return sections.flatMap(s => s.items);
