  1→import {
  2→  type ReactNode,
  3→  type RefObject,
  4→  useCallback,
  5→  useEffect,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './actions_dropdown.scss';
 10→
 11→export interface DropdownAction {
 12→  label: string;
 13→  shortcut?: ReactNode;
 14→  onClick?: () => void;
 15→}
 16→
 17→interface ActionsDropdownProps {
 18→  actions: DropdownAction[];
 19→  open: boolean;
 20→  onClose: () => void;
 21→  triggerRef?: RefObject<HTMLButtonElement | null>;
 22→}
 23→
 24→export function ActionsDropdown({
 25→  actions,
 26→  open,
 27→  onClose,
 28→  triggerRef,
 29→}: ActionsDropdownProps) {
 30→  const [activeIndex, setActiveIndex] = useState(0);
 31→  const dropdownRef = useRef<HTMLDivElement>(null);
 32→
 33→  useEffect(() => {
 34→    if (open && dropdownRef.current) {
 35→      setActiveIndex(0);
 36→      dropdownRef.current.focus();
 37→    }
 38→  }, [open]);
 39→
 40→  const executeAction = useCallback(
 41→    (index: number) => {
 42→      actions[index]?.onClick?.();
 43→      onClose();
 44→    },
 45→    [
 46→      actions,
 47→      onClose,
 48→    ],
 49→  );
 50→
 51→  useEffect(() => {
 52→    if (!open) return;
 53→
 54→    function handleKeyDown(e: KeyboardEvent) {
 55→      if (e.key === 'k' && e.metaKey) {
 56→        e.preventDefault();
 57→        e.stopPropagation();
 58→        onClose();
 59→        return;
 60→      }
 61→
 62→      if (e.key === 'Escape') {
 63→        e.preventDefault();
 64→        e.stopPropagation();
 65→        onClose();
 66→        return;
 67→      }
 68→
 69→      if (e.key === 'ArrowDown') {
 70→        e.preventDefault();
 71→        e.stopPropagation();
 72→        setActiveIndex(i => (i < actions.length - 1 ? i + 1 : 0));
 73→        return;
 74→      }
 75→
 76→      if (e.key === 'ArrowUp') {
 77→        e.preventDefault();
 78→        e.stopPropagation();
 79→        setActiveIndex(i => (i > 0 ? i - 1 : actions.length - 1));
 80→        return;
 81→      }
 82→
 83→      if (e.key === 'Enter') {
 84→        e.preventDefault();
 85→        e.stopPropagation();
 86→        executeAction(activeIndex);
 87→      }
 88→    }
 89→
 90→    window.addEventListener('keydown', handleKeyDown, true);
 91→    return () => window.removeEventListener('keydown', handleKeyDown, true);
 92→  }, [
 93→    open,
 94→    actions.length,
 95→    activeIndex,
 96→    onClose,
 97→    executeAction,
 98→  ]);
 99→
100→  useEffect(() => {
101→    if (!open) return;
102→
103→    function handleClickOutside(e: MouseEvent) {
104→      const target = e.target as Node;
105→      if (dropdownRef.current && !dropdownRef.current.contains(target)) {
106→        if (triggerRef?.current?.contains(target)) return;
107→        onClose();
108→      }
109→    }
110→
111→    document.addEventListener('mousedown', handleClickOutside);
112→    return () => document.removeEventListener('mousedown', handleClickOutside);
113→  }, [
114→    open,
115→    onClose,
116→    triggerRef,
117→  ]);
118→
119→  useEffect(() => {
120→    if (!open) return;
121→    const container = dropdownRef.current;
122→    if (!container) return;
123→
124→    const activeElement = container.querySelector<HTMLElement>(
125→      `[data-dropdown-index="${activeIndex}"]`,
126→    );
127→    activeElement?.scrollIntoView({ block: 'nearest' });
128→  }, [
129→    open,
130→    activeIndex,
131→  ]);
132→
133→  if (!open || actions.length === 0) return null;
134→
135→  return (
136→    <div
137→      className="actions-dropdown"
138→      ref={dropdownRef}
139→      role="menu"
140→      aria-label="Available actions"
141→      tabIndex={-1}
142→    >
143→      {actions.map((action, index) => (
144→        <button
145→          key={action.label}
146→          id={`action-item-${index}`}
147→          className={`actions-dropdown__item${index === activeIndex ? ' actions-dropdown__item--active' : ''}`}
148→          data-dropdown-index={index}
149→          role="menuitem"
150→          type="button"
151→          onClick={() => executeAction(index)}
152→          onMouseEnter={() => setActiveIndex(index)}
153→        >
154→          <span className="actions-dropdown__label">{action.label}</span>
155→          {action.shortcut && (
156→            <span className="actions-dropdown__shortcut">
157→              {action.shortcut}
158→            </span>
159→          )}
160→        </button>
161→      ))}
162→    </div>
163→  );
164→}
